1	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [ 0, -1],          [ 0, 1],
4	  [ 1, -1], [ 1, 0], [ 1, 1],
5	];
6	
7	const willBeAlive = (neighborCount: number, isCurrentlyAlive: boolean): boolean =>
8	  neighborCount === 3 || (neighborCount === 2 && isCurrentlyAlive);
9	
10	const countLivingNeighbors = (livingCells: Set<string>): Map<string, number> => {
11	  const counts = new Map<string, number>();
12	  for (const cell of livingCells) {
13	    const [x, y] = cell.split(",").map(Number);
14	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
15	      const neighborKey = `${x + dx},${y + dy}`;
16	      counts.set(neighborKey, (counts.get(neighborKey) ?? 0) + 1);
17	    }
18	  }
19	  return counts;
20	};
21	
22	export function nextGeneration(livingCells: Set<string>): Set<string> {
23	  const neighborCounts = countLivingNeighbors(livingCells);
24	  const result = new Set<string>();
25	  for (const [cell, count] of neighborCounts) {
26	    if (willBeAlive(count, livingCells.has(cell))) {
27	      result.add(cell);
28	    }
29	  }
30	  return result;
31	}
